## main.cpp

```c++
#include <iostream>
#include <fstream>
#include <string>
#include <cmath>

#include "QuadTree.h"
#include "FileReadAndOut.h"
#include "Gaussian.h"

int main() 
{
    int height, width; double key; string filename; char Choice = 'Y';                                // 定义变量

    cout << "请输入文件路径(不包含双引号)："; cin >> filename;
    cout << "文件读取中。。。。。。" << endl;
    int*** ImageData = Read_File_Data(filename, height, width);      if (!ImageData)return -1;        // 读取文件数据
    int*** ImageDataGauss = Read_File_Data(filename, height, width); if (!ImageData)return -1;        // 读取文件数据

    cout << "均值模糊?[y/n]:\t";
    cin  >>  Choice;
    if (Choice == 'Y' || Choice == 'y'){
        cout << "//----------------------------均值模糊-------------------------------//" << endl;
        cout << "请输入阈值：";                   cin >> key;

        QuadTree tree(0, 0, width, height,ImageData, height, width);                                 // 建立四叉树
        tree.Divide(ImageData, height, width, key);                                                  // 四叉树分割

        tree.MeanBlur(ImageData, height, width);                                                     // 均值模糊处理
        Out_File_Data(filename+"_MeanBlur.ppm", ImageData, height, width);                           // 输出文件数据
    }

    cout << "高斯模糊?[y/n]:\t";
    cin >> Choice;
    if (Choice == 'Y' || Choice == 'y') {
        cout << "//----------------------------高斯模糊-------------------------------//" << endl;
        cout << "输入高斯模糊程度(大于1):";       cin >> key;
        GaussianBlur(ImageDataGauss, height, width, key);                                            // 高斯模糊处理
        Out_File_Data(filename + "_GaussianBlur.ppm", ImageDataGauss, height, width);                // 输出文件数据
    }

    cout << "//----------------------------处理完成-------------------------------//" << endl;
    cout << "//-------------------------------------------------------------------//" << endl;
    Delete_Data(ImageData, height, width);                                                           // 释放内存
    return 0;
}
```

## QuadTree.h

```c++
#pragma once
#include <vector>
#include <cmath>

using namespace std;

class QuadTree {
private:
    int x, y, w, h;                     //四叉树的位置和大小
    double ColorAverage, EColor;        //均值和方差
    bool Divided;                       //是否分割
    QuadTree* topLeft;
    QuadTree* topRight;
    QuadTree* bottomLeft;
    QuadTree* bottomRight;

public:
    QuadTree(int x, int y, int w, int h, int*** ImageData, int Width, int Height) :
        x(x), y(y), w(w), h(h), ColorAverage(0), EColor(0), Divided(false), topLeft(nullptr), topRight(nullptr), bottomLeft(nullptr), bottomRight(nullptr)
    {
        int l = w * h;
        vector<double> colord(l);
        double sum = 0.0;

        for (int i = y; i < (y + h); i++) {
            for (int j = x; j < (x + w); j++) {
                colord[(i - y) * w + (j - x)] = sqrt((pow(ImageData[i][j][0], 2) + pow(ImageData[i][j][1], 2) + pow(ImageData[i][j][2], 2)) / 3);
                sum += colord[(i - y) * w + (j - x)];
            }
        }

        ColorAverage = sum / l;

        for (int i = 0; i < l; i++) EColor += pow(colord[i] - ColorAverage, 2);
        EColor = sqrt(EColor / l);
    }

    ~QuadTree() {
        delete topLeft;
        delete topRight;
        delete bottomLeft;
        delete bottomRight;
    }

    void Divide(int*** ImageData, int Width, int Height, double key) {
        if ((w == 1 && h == 1) || (EColor <= key)) return;

        Divided = true;
        int newW = w / 2;
        int newH = h / 2;

        topLeft = new QuadTree(x, y, newW, newH, ImageData, Width, Height);
        topRight = new QuadTree(x + newW, y, newW, newH, ImageData, Width, Height);
        bottomLeft = new QuadTree(x, y + newH, newW, newH, ImageData, Width, Height);
        bottomRight = new QuadTree(x + newW, y + newH, newW, newH, ImageData, Width, Height);

        topLeft->Divide(ImageData, Width, Height, key);
        topRight->Divide(ImageData, Width, Height, key);
        bottomLeft->Divide(ImageData, Width, Height, key);
        bottomRight->Divide(ImageData, Width, Height, key);
    }

    void MeanBlur(int*** ImageData, int Width, int Height) {
        if (Divided) {
            topLeft->MeanBlur(ImageData, Width, Height);
            topRight->MeanBlur(ImageData, Width, Height);
            bottomLeft->MeanBlur(ImageData, Width, Height);
            bottomRight->MeanBlur(ImageData, Width, Height);
        }
        else {
            int l = w * h;
            int* RGB = new int[3] {0, 0, 0};

            for (int i = y; i < y + h; i++) {
                for (int j = x; j < x + w; j++) {
                    for (int k = 0; k < 3; k++) {
                        RGB[k] += ImageData[i][j][k];
                    }
                }
            }
            for (int k = 0; k < 3; k++) RGB[k] /= l;

            for (int i = y; i < (y + h); i++) {
                for (int j = x; j < (x + w); j++) {
                    for (int k = 0; k < 3; k++) {
                        ImageData[i][j][k] = RGB[k];
                    }
                }
            }
        }
    }
};
```

